<nowiki>
.underline-effect {
  position: relative;
  display: inline-block;
  font-size: 16px;
  text-decoration: none;
}

.underline-effect::before {
  content: '';
  position: absolute;
  width: 0;
  height: 2px;
  bottom: 0;
  left: 50%;
  background-color: #a020f0;
  transition: all 0.3s ease-out;
}

.underline-effect:hover::before {
  width: 100%;
  left: 0;
}
</nowiki>}}

